    UIViewController *oldViewController = [self.childViewControllers firstObject];
    UIViewController *newViewController = [self.childViewControllers objectAtIndex:sender.selectedSegmentIndex];

    // Swap the views
    [self.containerView exchangeSubviewAtIndex:0 withSubviewAtIndex:1];

    // Animate the transition
    [UIView transitionWithView:self.containerView
                      duration:0.5
                       options:UIViewAnimationOptionTransitionCrossDissolve
                    animations:^{
                        // No need for any animations here, the transition is handled by the exchangeSubviewAtIndex method
                    }
